import os
import re
from pathlib import Path

REPO_ROOT = Path(os.environ.get("REPO_ROOT", ".")).resolve()
MAX_FILE_LINES = 500
MAX_SEARCH_MATCHES = 50

def _safe_path(rel: str) -> Path | None:
    try:
        p = (REPO_ROOT / rel).resolve()
        p.relative_to(REPO_ROOT)
        return p
    except (ValueError, Exception):
        return None

def handle_list_directory(path: str, show_hidden: bool = False) -> dict:
    p = _safe_path(path)
    if p is None or not p.is_dir():
        return {"error": "INVALID_PATH"}
    entries = [
        {"name": e.name, "type": "directory" if e.is_dir() else "file",
         "size_bytes": e.stat().st_size if e.is_file() else None}
        for e in sorted(p.iterdir())
        if show_hidden or not e.name.startswith(".")
    ]
    return {"path": path, "entries": entries[:200], "count": len(entries)}

