import subprocess
from pathlib import Path

def ripgrep_search(pattern: str, repo_root: str, file_glob: str = None,
                   max_matches: int = 50) -> dict:
    """Fast codebase search using ripgrep (rg)."""
    cmd = [
        "rg",
        "--json",
        "--max-filesize", "1M",
        "-m", str(max_matches),
    ]
    if file_glob:
        cmd += ["--glob", file_glob]
    cmd += [pattern, repo_root]

    try:
        result = subprocess.run(
            cmd, capture_output=True, text=True, timeout=10
        )
    except subprocess.TimeoutExpired:
        return {"error": "TIMEOUT", "matches": []}
    except FileNotFoundError:
        # rg not installed -- fall back to Python
        return handle_search_codebase(pattern, file_glob or "**/*")

    import json as _json
    matches = []
    for line in result.stdout.splitlines():
        try:
            obj = _json.loads(line)
        except _json.JSONDecodeError:
            continue
        if obj.get("type") == "match":
            data = obj["data"]
            matches.append({
                "file": str(Path(data["path"]["text"]).relative_to(repo_root)),
                "line": data["line_number"],
                "text": data["lines"]["text"].rstrip(),
            })
    return {"matches": matches, "truncated": len(matches) >= max_matches}
